features.snippet:
fifo_mem[0:1];
reg [1:0] fifo_count;
reg fifo_rd_addr;
reg fifo_wr_addr;

always_ff @(posedge clk) begin
  fifo_rd_addr <= _GEN ? fifo_rd_addr - 1'h1 : fifo_rd_addr;
  fifo_wr_addr <= _GEN_0 ? fifo_wr_addr - 1'h1 : fifo_wr_addr;
end

reg [31:0] fifo_mem[0:1];
fifo_mem[fifo_wr_addr] <= push_in;
assign pop_out = fifo_mem[fifo_rd_addr];

assign _GEN = |fifo_count;
assign _GEN_0 = fifo_count != 2'h2;
fifo_rd_addr <= _GEN ? fifo_rd_addr - 1'h1 : fifo_rd_addr;
